const root = $('Website Form Lead Webhook').first().json;
const body = root.body && typeof root.body === 'object' && !Array.isArray(root.body) ? root.body : root;

const pick = (obj, keys) => {
  if (!obj || typeof obj !== 'object') return '';
  for (const k of keys) {
    const v = obj[k];
    if (v !== undefined && v !== null && String(v).trim()) return String(v).trim();
  }
  return '';
};

const contactId = pick(body, ['contactId', 'contact_id', 'hs_object_id', 'vid', 'objectId']) || pick(root, ['contactId', 'contact_id', 'hs_object_id']);
const createDeal = body.createDeal === false || body.createDeal === 'false' ? false : true;
const dealStage = pick(body, ['dealStage', 'deal_stage']) || '';
const tier = pick(body, ['tier']) || 'starter';
const painOverride = pick(body, ['painOverride', 'message', 'notes', 'pain']) || '';
const amount = body.amount !== undefined && body.amount !== null && body.amount !== '' ? Number(body.amount) : null;

return [{ json: { contactId, createDeal, dealStage, tier, painOverride, amount: Number.isFinite(amount) ? amount : null } }];

const parse = $('Parse Webhook Input').first().json;
const raw = $('Get Contact').first().json;
const p = raw.properties || raw;
const v = (x) => {
  if (x === undefined || x === null) return '';
  if (typeof x === 'object' && 'value' in x) return String(x.value ?? '').trim();
  return String(x).trim();
};
const company = v(p.company);
const first = v(p.firstname);
const last = v(p.lastname);
const pain = (parse.painOverride || v(p.pain_point) || '').trim();
const dealName = `${company || first || 'Website lead'} - Website`;
const stage = parse.dealStage || 'qualifiedtobuy';
const amount = parse.amount != null ? parse.amount : 0;
return [{ json: {
  contactId: parse.contactId,
  dealName,
  company,
  firstname: first,
  lastname: last,
  stage,
  amount,
  industry: v(p.industry),
  painPoint: pain,
  tier: parse.tier || 'starter'
}}];

